import base64, json, urllib.request, os

# Read the image and encode to base64
with open('/tmp_workspace/poster_original.png', 'rb') as f:
    img_data = base64.b64encode(f.read()).decode('utf-8')

base_url = os.environ.get('OPENROUTER_BASE_URL', 'http://localhost:8000/v1')
api_key = os.environ.get('OPENROUTER_API_KEY', 'dummy')

payload = {
    'model': 'openai/gpt-4o',
    'messages': [
        {
            'role': 'user',
            'content': [
                {
                    'type': 'image_url',
                    'image_url': {'url': f'data:image/png;base64,{img_data}'}
                },
                {
                    'type': 'text',
                    'text': '''Analyze this social media poster carefully. The image is 2746x1371 pixels (landscape).

Please provide:
1. A description of all main elements (subjects, text, logos, graphics)
2. Where the PRIMARY visual focus/subject is located - give as percentage from left (x%) and from top (y%)
3. A recommended SAFE ZONE bounding box that contains all key content - as percentages: left%, top%, right%, bottom%
4. Any elements near edges that must not be cropped
5. The single best center point for smart cropping - x%, y% from top-left

Be precise with coordinates.'''
                }
            ]
        }
    ],
    'max_tokens': 1000
}

data = json.dumps(payload).encode('utf-8')
req = urllib.request.Request(
    f'{base_url}/chat/completions',
    data=data,
    headers={
        'Content-Type': 'application/json',
        'Authorization': f'Bearer {api_key}'
    }
)

try:
    with urllib.request.urlopen(req, timeout=60) as resp:
        result = json.loads(resp.read().decode('utf-8'))
        print(result['choices'][0]['message']['content'])
except Exception as e:
    print(f'ERROR: {e}')
"

