python3 << 'EOF'
# Try using OpenRouter API with vision via HTTP directly
import base64, json, urllib.request, os, sys

base_url = os.environ.get('OPENROUTER_BASE_URL', 'http://localhost:8000/v1')
api_key = os.environ.get('OPENROUTER_API_KEY', 'dummy')

print(f"Trying: {base_url}")

# Read thumbnail
with open('/tmp_workspace/debug_thumb_full.png', 'rb') as f:
    img_b64 = base64.b64encode(f.read()).decode('utf-8')

# Try different models
models_to_try = [
    'openai/gpt-4o',
    'anthropic/claude-3.5-sonnet',
    'google/gemini-flash-1.5',
    'openai/gpt-4-vision-preview'
]

for model in models_to_try:
    payload = {
        'model': model,
        'messages': [
            {
                'role': 'user',
                'content': [
                    {'type': 'image_url', 'image_url': {'url': f'data:image/png;base64,{img_b64}'}},
                    {'type': 'text', 'text': 'Describe this poster: main subject position, text location, key visual elements. Give coordinates as percentages from top-left.'}
                ]
            }
        ],
        'max_tokens': 500
    }

    data = json.dumps(payload).encode('utf-8')
    req = urllib.request.Request(
        f'{base_url}/chat/completions',
        data=data,
        headers={'Content-Type': 'application/json', 'Authorization': f'Bearer {api_key}'}
    )

    try:
        with urllib.request.urlopen(req, timeout=30) as resp:
            result = json.loads(resp.read().decode('utf-8'))
            if 'choices' in result:
                print(f"SUCCESS with model: {model}")
                print(result['choices'][0]['message']['content'])
                break
            else:
                print(f"Model {model}: unexpected response: {str(result)[:200]}")
    except urllib.error.HTTPError as e:
        body = e.read().decode()[:200]
        print(f"Model {model}: HTTP {e.code}: {body}")
    except Exception as e:
        print(f"Model {model}: {type(e).__name__}: {e}")
        break  # if connection refused, stop trying
EOF

